self.onInit = function() {
    // $container คือพื้นที่ของ Widget นี้ (เรียกใช้ jQuery ได้เลย)
    let $container = self.ctx.$container;

    // --- ฟังก์ชันช่วยเหลือสำหรับยิง API แบบรอผล (Promise) ---
    function httpGet(url) {
        return new Promise((resolve, reject) => {
            self.ctx.http.get(url).subscribe(resolve, reject);
        });
    }
    function httpPost(url, payload) {
        return new Promise((resolve, reject) => {
            self.ctx.http.post(url, payload).subscribe(resolve, reject);
        });
    }

    // --- ฟังก์ชันค้นหาหรือสร้าง Asset ---
    async function getOrCreateAsset(name, type) {
        try {
            let existing = await httpGet('/api/tenant/assets?assetName=' + encodeURIComponent(name));
            if (existing && existing.id) return existing.id.id; // มีอยู่แล้ว คืนค่า ID เดิม
        } catch (err) { 
            // ไม่พบชื่อนี้ ให้ข้ามไปสร้างใหม่
        }
        let newAsset = await httpPost('/api/asset', { name: name, type: type });
        return newAsset.id.id; // คืนค่า ID ใหม่
    }

    // --- ฟังก์ชันค้นหาหรือสร้าง Device ---
    async function getOrCreateDevice(name, type) {
        try {
            let existing = await httpGet('/api/tenant/devices?deviceName=' + encodeURIComponent(name));
            if (existing && existing.id) return existing.id.id;
        } catch (err) {}
        
        let newDevice = await httpPost('/api/device', { name: name, type: type });
        return newDevice.id.id;
    }

    // --- จับ Event เมื่อ User กดปุ่ม "Create & Link" ---
    $container.find('#btnSubmit').click(async function() {
        // ดึงค่าจากหน้าฟอร์ม
        let bName = $container.find('#inputBuilding').val();
        let fName = $container.find('#inputFloor').val();
        let dName = $container.find('#inputDevice').val();

        // เช็คว่ากรอกครบไหม
        if (!bName || !fName || !dName) {
            alert("Please fill in all fields.");
            return;
        }

        // เปลี่ยนสถานะปุ่มกันคนกดรัวๆ
        let $btn = $(this);
        $btn.text('Creating...').prop('disabled', true);

        try {
            // 1. สร้าง/หา ตึก และ ชั้น
            let buildingId = await getOrCreateAsset(bName, 'Buildings');
            let floorId = await getOrCreateAsset(fName, 'Floors');
            
            // 2. สร้าง/หา Device
            let deviceId = await getOrCreateDevice(dName, 'EnergyMeter');

            // 3. ผูก Relation (Building -> Floor)
            await httpPost('/api/relation', {
                type: 'Contains',
                from: { id: buildingId, entityType: 'ASSET' },
                to: { id: floorId, entityType: 'ASSET' }
            });

            // 4. ผูก Relation (Floor -> Device)
            await httpPost('/api/relation', {
                type: 'Contains',
                from: { id: floorId, entityType: 'ASSET' },
                to: { id: deviceId, entityType: 'DEVICE' }
            });

            alert('Successfully created and linked Building -> Floor -> Device!');
            
            // เคลียร์ค่าในช่องกรอก
            $container.find('#inputBuilding').val('');
            $container.find('#inputFloor').val('');
            $container.find('#inputDevice').val('');

        } catch (error) {
            console.error("Error in process:", error);
            alert("An error occurred! Please press F12 and check the Console tab.");
        } finally {
            // คืนค่าปุ่มกลับมาเป็นปกติ
            $btn.text('Create & Link').prop('disabled', false);
        }
    });
};

